#include <bits/stdc++.h>
#define R register
using namespace std;
priority_queue<long long,vector<long long>,greater<long long> > p;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    R long long n,ans=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        R long long a;
        cin>>a;
        p.push(a);
    }
    while(p.size()-1){
        R long long x,y;
        x=p.top(),p.pop(),y=p.top(),p.pop();
        ans+=x+y;
        p.push(x+y);
    }
    cout<<ans;
    return 0;
}
